import{_ as d,o as r,c as a,ai as e}from"./chunks/framework.CaiDwmc7.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01 Геймдизайн/Пчелы/Индикаторы для игрока.md","filePath":"01 Геймдизайн/Пчелы/Индикаторы для игрока.md"}'),_={name:"01 Геймдизайн/Пчелы/Индикаторы для игрока.md"};function h(o,t,n,s,i,l){return r(),a("div",null,[...t[0]||(t[0]=[e('<h3 id="состояние-семьи" tabindex="-1">Состояние семьи <a class="header-anchor" href="#состояние-семьи" aria-label="Permalink to “Состояние семьи”">​</a></h3><table tabindex="0"><thead><tr><th>Параметр</th><th>Что видит игрок (пример)</th><th>Визуализация</th><th>Комментарий</th></tr></thead><tbody><tr><td>Сила семьи</td><td>4/5</td><td>Полоска с заполнением</td><td>суммарный показатель здоровья и продуктивности</td></tr><tr><td>Популяция</td><td>12 340 пчел</td><td>Число + иконка</td><td>Сколько всего пчел в улье</td></tr><tr><td>Рабочие пчелы</td><td>10 200</td><td>Число + иконка (иконка рабочей пчелы)</td><td>Основная рабочая сила. Следить за динамикой</td></tr><tr><td>Трутни</td><td>340</td><td>Число + иконка (иконка трутня)</td><td>Есть ли избыток. Осенью должны обнуляться</td></tr><tr><td>Расплод</td><td>4 500</td><td>Число + иконка (иконка личинки)</td><td>Будущее семьи. Если мало - проблемы с маткой</td></tr><tr><td>Мед в улье</td><td>18,4 кг</td><td>Число + иконка (банка меда)</td><td>Общий запас. Критичный показатель для зимы</td></tr><tr><td>Перга</td><td>2,3 кг</td><td>Число + иконка (цветочная пыльца)</td><td>Корм для расплода. Без нее личинки не будут расти</td></tr><tr><td>Свободные ячейки</td><td>1200</td><td>Число + иконка (пустые слоты)</td><td>Место для расширения. Если 0 - нужны новые рамки</td></tr><tr><td>Возраст матки</td><td>2 года</td><td>Число + иконка (корона)</td><td>Пора ли менять</td></tr></tbody></table><h3 id="детализация-популяции" tabindex="-1">Детализация популяции <a class="header-anchor" href="#детализация-популяции" aria-label="Permalink to “Детализация популяции”">​</a></h3><table tabindex="0"><thead><tr><th>Параметр</th><th>Что видит игрок</th><th>Визуализация</th><th>Комментарий</th></tr></thead><tbody><tr><td><strong>Внутренние пчелы</strong></td><td>Общее количество, Число + иконка</td><td>Иконка улья</td><td>Работают внутри улья. Основа семьи</td></tr><tr><td>- уборщицы</td><td>Число + иконка</td><td>Веник</td><td>Чистят ячейки. Если мало - грязь, болезни</td></tr><tr><td>- кормилицы</td><td>Число + иконка</td><td>соска</td><td>Кормят расплод. Если мало - расплод голодает</td></tr><tr><td>- строительницы</td><td>Число + иконка</td><td>молоток</td><td>Строят соты. если мало - нет новых ячеек</td></tr><tr><td>- приемщицы</td><td>Число + иконка</td><td>руки</td><td>Принимают нектар. Если мало - затор у входа</td></tr><tr><td>- вентиляторщицы</td><td>Число + иконка</td><td>вентилятор</td><td>Охлаждают/сушат. В жару критично</td></tr><tr><td>- охранницы</td><td>Число + иконка</td><td>щит</td><td>Защищают вход. Если мало - воровство</td></tr><tr><td><strong>Фуражиры</strong></td><td>Общее количество, Число + иконка</td><td>Крыло</td><td>Летают за ресурсами. Главные добытчики</td></tr><tr><td>- нектарные</td><td>Число + иконка</td><td>капля меда</td><td>Собирают нектар. Основа медосбора</td></tr><tr><td>- пыльцевые</td><td>Число + иконка</td><td>цветок с пыльцой</td><td>Собирают пыльцу. Нужны для создания перги</td></tr><tr><td>- водоносы</td><td>Число + иконка</td><td>капля воды</td><td>Носят воду. В жару спасают улей</td></tr><tr><td>- прополисные</td><td>Число + иконка</td><td>смола</td><td>Собирают прополис. Заклеивают щели</td></tr><tr><td>- разведчицы</td><td>Число + иконка</td><td>глаз</td><td>Ищут новые места. Опрелеояют эффективность медосбора</td></tr></tbody></table>',4)])])}const m=d(_,[["render",h]]);export{b as __pageData,m as default};
